CREATE OR REPLACE FUNCTION fpb_get_tnl ( as_memno char , as_field char ) RETURNS bigint AS $body$
DECLARE

ldc_prin bigint;
ldc_int bigint;

BEGIN
 SELECT sum(sc_com_m_receipt_item.principal_amount ),
        sum(sc_com_m_receipt_item.interest_amount)
   into STRICT ldc_prin, ldc_int
    FROM sc_com_m_receipt,
         sc_com_m_receipt_item
   WHERE ( sc_com_m_receipt_item.receipt_no = sc_com_m_receipt.receipt_no ) and ( sc_com_m_receipt.membership_no = as_memno ) AND ( sc_com_m_receipt.money_type_id = 'TNL' ) AND ( sc_com_m_receipt.receipt_status = '0' );

  if coalesce(ldc_prin::text, '') = '' then ldc_prin := 0;end if;
  if coalesce(ldc_int::text, '') = '' then ldc_int := 0;end if;

  case trim(both as_field )
   when 'prin' THEN
      return ldc_prin;
   when 'int' THEN
      return ldc_int;
   else
      return ldc_prin + ldc_int;
   end case;

END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
